node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for semantic HTML elements
if (!/<main|<section|<article|<nav|<aside|<header|<footer/.test(content)) {
  issues.push('⚠ Missing semantic HTML elements (use <main>, <section>, <header>, etc.)');
}

// Check for aria-label on interactive elements without text
if (/<button[^>]*>\s*<svg|<button[^>]*>\s*<i/.test(content) && !/<button[^>]*aria-label/.test(content)) {
  issues.push('⚠ Icon-only buttons missing aria-label attribute');
}

// Check for form labels
if (/<input[^>]*type=\"(text|search)/.test(content) && !/<label[^>]*for=/.test(content)) {
  issues.push('⚠ Input elements should have associated <label> elements');
}

// Check for lang attribute
if (!/<html[^>]*lang/.test(content)) issues.push('⚠ <html> tag missing lang attribute (use lang=\"sv\" for Swedish)');

// Check for meta description
if (!/<meta[^>]*name=\"description/.test(content)) issues.push('ℹ No meta description found (improves SEO)');

// Check for aria-hidden on decorative elements
if (/<svg[^>]*>.*<\/svg>/.test(content) && !/<svg[^>]*aria-hidden/.test(content)) {
  issues.push('ℹ Decorative <svg> elements should have aria-hidden=\"true\"');
}

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log('✓ Accessibility & SEO check passed');
}
" -- '{FILE}' || true

node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for keyboard navigation support
if (/addEventListener.*click/g.test(content) && !/addEventListener.*keydown|addEventListener.*keypress/.test(content)) {
  issues.push('ℹ Check that keyboard navigation is supported for click handlers');
}

// Check for ARIA live regions (for dynamic content)
if (/render\(\)|updateMapMarkers\(\)/.test(content) && !/(aria-live|aria-atomic|role=)/.test(content)) {
  issues.push('ℹ Dynamic content updates may benefit from aria-live regions');
}

// Check for focus management
if (!/(focus\(\)|document\.activeElement)/.test(content)) {
  issues.push('ℹ Consider focus management after modal/panel changes');
}

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log('✓ JavaScript accessibility check passed');
}
" -- '{FILE}' || true
